// Content-negotiated 404s. A genuinely-unknown path is served as the HTML
// not-found page to browsers, but as a structured RFC 9457-shaped JSON body
// (application/json) to agents — so a programmatic client gets a parseable
// error instead of scraping HTML.
//
// Why: orank's "JSON error responses" check + its agent reviewer both probed
// root-level conventional paths (/checkout_sessions, /.well-known/oauth-*) and
// got HTML 404s. The /api/* catch-all already returns the JSON error; this
// widens the same guarantee to the whole origin without fabricating any
// endpoint — a 404 is the honest answer, just made machine-readable.

// Real top-level paths we serve. Anything outside this set is a true 404, so it
// is safe to answer agents with JSON. Kept in sync with the route tree by
// agent-404.test.ts, which derives the actual routes from app/ and fails if one
// is missing here.
export const SERVED_EXACT: ReadonlySet<string> = new Set([
	"/",
	"/about",
	"/alternatives",
	"/best-claude-code-plugins",
	"/claude-agent-sdk-vs-claude-code-plugins",
	"/compare",
	"/contact",
	"/developers",
	"/pricing",
	"/privacy",
	"/status",
	"/terms",
	"/yonyon",
	// Top-level route files (markdown twins, feeds, sitemaps, OG image).
	"/auth.md",
	"/api-policy.md",
	"/pricing.md",
	"/llms.txt",
	"/llms-full.txt",
	"/schema-map.xml",
	"/robots.txt",
	"/sitemap.xml",
	"/opengraph-image",
	"/favicon.svg",
	// next.config rewrites that land on real handlers.
	"/ask",
	"/mcp.json",
	// Specific /.well-known/* paths we actually rewrite to handlers. Listed
	// individually (not as a prefix) so UNKNOWN well-known probes — e.g.
	// /.well-known/oauth-authorization-server, which we don't serve (no
	// authorization server exists) — still get a structured JSON 404 for
	// agents instead of an HTML page. Kept in sync with next.config.mjs by
	// agent-404.test.ts.
	"/.well-known/agent-skills/index.json",
	"/.well-known/oauth-protected-resource",
	"/.well-known/api-catalog",
	"/.well-known/agent-card.json",
	"/.well-known/mcp",
	"/.well-known/mcp/server-card.json",
	"/.well-known/mcp.json",
	"/.well-known/mcp/manifest.json",
]);

// Prefix-served namespaces (their own routing decides 200 vs structured 404).
export const SERVED_PREFIXES: readonly string[] = [
	"/docs",
	"/api",
	"/_next",
	"/thumbnails",
];

export function isServedPath(pathname: string): boolean {
	if (SERVED_EXACT.has(pathname)) return true;
	for (const prefix of SERVED_PREFIXES) {
		if (pathname === prefix || pathname.startsWith(`${prefix}/`)) return true;
	}
	// Static assets (anything with a file extension) — let Next serve or 404 them
	// natively rather than synthesizing a JSON error for a missing image/font.
	// EXCEPTION: .json is a data format agents probe (e.g. /product_feed.json, an
	// Agentic-Commerce feed) — an unknown one should get a structured JSON 404,
	// not an HTML page. Every .json we actually serve is in SERVED_EXACT above, so
	// excluding it here only reroutes genuine 404s to the machine-readable answer.
	if (/\.[a-z0-9]+$/i.test(pathname) && !pathname.endsWith(".json")) return true;
	return false;
}

// A request prefers a JSON error unless it is a browser explicitly asking for
// HTML. `*/*` (curl, most SDKs) and JSON-typed Accepts both get JSON.
export function prefersJsonError(accept: string): boolean {
	return !accept.includes("text/html");
}

// Whether middleware should answer this request with a structured JSON 404
// instead of letting it fall through to the HTML not-found page.
export function shouldJsonError(
	method: string,
	pathname: string,
	accept: string,
): boolean {
	if (method === "OPTIONS") return false; // never hijack a CORS preflight
	return !isServedPath(pathname) && prefersJsonError(accept);
}
